sql:
SELECT mode_of_transport, AVG(fuel_consumption) AS average_fuel_consumption
FROM transportation_legs
GROUP BY mode_of_transport;

SELECT mode_of_transport, AVG(speed) AS average_speed
FROM transportation_legs
WHERE mode_of_transport = 'train';

SELECT T.from_location, T.to_location, V.vehicle_type, V.capacity
FROM transportation_legs AS T
INNER JOIN vehicles AS V ON T.from_location = V.current_location OR T.to_location = V.current_location;

SELECT AVG(fuel_consumption) AS AverageFuelConsumption
FROM transportation_legs
WHERE driver_id = 1;

SELECT SUM(s.weight) AS total_weight
FROM shipments s
WHERE s.delivery_date LIKE '2023-10%' AND s.status = 'delivered';

external_knowledge:
- 'captain of the fleet' refers to the driver with user_id 1; 
- 'cargo load' refers to the volume of shipments; 
- 'vessels' refers to the shipments; 
- 'green light to set sail' refers to an 'active' status.
